) l;

INSERT INTO astrology_kb (
  id, kind, key1, key2, key3, locale, title, content, short_summary, tone, source, author, image_url, is_active
)
SELECT
  UUID(),
  'sign_section',
  s.sign_key,
  t.topic_key,
  NULL,
  l.locale,
  CASE l.locale
    WHEN 'tr' THEN CONCAT(s.label_tr, ' Burcu ', t.title_tr)
    WHEN 'de' THEN CONCAT(s.label_de, ' und ', t.title_de)
    ELSE CONCAT(s.label_en, ' and ', t.title_en)
  END,
  CASE l.locale
    WHEN 'tr' THEN CONCAT(s.label_tr, ' için ', t.title_tr, ' başlığı ', t.focus_tr, ' üzerinden okunur. ', s.core_tr, ' Bu nedenle bu alanda en iyi sonuç, burcun doğal ritmini bastırmadan onu bilinçli bir seçime dönüştürmekle gelir. ', t.practice_tr, ' Gölge tarafta ', s.shadow_tr, ' bu konuyu zorlaştırabilir. Farkındalık arttıkça aynı enerji daha şefkatli, daha tutarlı ve daha üretken şekilde kullanılabilir.')
    WHEN 'de' THEN CONCAT('Für ', s.label_de, ' wird ', t.title_de, ' über ', t.focus_de, ' verstanden. ', s.core_de, ' Die besten Ergebnisse entstehen, wenn der natürliche Rhythmus nicht unterdrückt, sondern bewusst geführt wird. ', t.practice_de, ' Im Schatten können ', s.shadow_de, ' das Thema erschweren. Mit Bewusstsein wird dieselbe Energie freundlicher, klarer und produktiver.')
    ELSE CONCAT('For ', s.label_en, ', ', t.title_en, ' is understood through ', t.focus_en, '. ', s.core_en, ' The best results come when the natural rhythm is not suppressed but guided with awareness. ', t.practice_en, ' On the shadow side, ', s.shadow_en, ' can complicate this theme. With awareness, the same energy becomes kinder, clearer and more productive.')
  END,
  CASE l.locale
    WHEN 'tr' THEN CONCAT(s.label_tr, ' burcunun ', LOWER(t.title_tr), ' alanındaki temel dinamiği.')
    WHEN 'de' THEN CONCAT('Die zentrale Dynamik von ', s.label_de, ' in ', t.title_de, '.')
    ELSE CONCAT('The core ', t.title_en, ' dynamic for ', s.label_en, '.')
  END,
  'warm',
  'GoldMoodAstro Editorial',
  'GoldMoodAstro Editorial Team',
  NULL,
  1
FROM (
  SELECT 'aries' sign_key, 'Koç' label_tr, 'Aries' label_en, 'Widder' label_de, 'Koç cesaret, başlangıç ve doğrudan eylem arzusuyla çalışır.' core_tr, 'Aries works through courage, beginnings and direct action.' core_en, 'Widder wirkt durch Mut, Anfangskraft und direkte Handlung.' core_de, 'sabırsızlık, acele kararlar ve kontrolsüz rekabet' shadow_tr, 'impatience, rushed decisions and unmanaged competition' shadow_en, 'Ungeduld, vorschnelle Entscheidungen und unbewusster Wettbewerb' shadow_de
  UNION ALL SELECT 'taurus','Boğa','Taurus','Stier','Boğa istikrar, duyular, güven ve somut değerler üzerinden büyür.','Taurus grows through stability, senses, trust and tangible value.','Stier wächst durch Stabilität, Sinne, Vertrauen und greifbare Werte.','inat, değişime direnç ve konfor alanına aşırı tutunma','stubbornness, resistance to change and overattachment to comfort','Sturheit, Widerstand gegen Wandel und Festhalten am Komfort'
  UNION ALL SELECT 'gemini','İkizler','Gemini','Zwillinge','İkizler merak, bağlantı, öğrenme ve hızlı zihinsel geçişlerle canlı kalır.','Gemini stays alive through curiosity, connection, learning and mental agility.','Zwillinge leben durch Neugier, Verbindung, Lernen und geistige Beweglichkeit.','dağınıklık, yüzeysellik ve duygudan kaçmak için konuşmak','scattered focus, surface living and talking to avoid feeling','Zerstreuung, Oberflächlichkeit und Reden statt Fühlen'
  UNION ALL SELECT 'cancer','Yengeç','Cancer','Krebs','Yengeç hafıza, şefkat, aidiyet ve duygusal güvenlik ihtiyacıyla yön bulur.','Cancer navigates through memory, care, belonging and emotional safety.','Krebs orientiert sich durch Erinnerung, Fürsorge, Zugehörigkeit und emotionale Sicherheit.','alınganlık, kabuğa çekilme ve geçmişe fazla tutunma','sensitivity, retreating into the shell and holding the past too tightly','Empfindlichkeit, Rückzug und zu starkes Festhalten an der Vergangenheit'
  UNION ALL SELECT 'leo','Aslan','Leo','Löwe','Aslan yaratıcı ifade, kalp açıklığı, görünürlük ve onurlu liderlik ister.','Leo seeks creative expression, open-heartedness, visibility and noble leadership.','Löwe sucht kreativen Ausdruck, Herzenswärme, Sichtbarkeit und würdevolle Führung.','gurur, dramatizasyon ve ilgi eksikliğini kişisel almak','pride, dramatization and taking lack of attention personally','Stolz, Dramatisierung und fehlende Aufmerksamkeit persönlich nehmen'
  UNION ALL SELECT 'virgo','Başak','Virgo','Jungfrau','Başak hizmet, düzen, analiz ve küçük iyileştirmelerin büyük etkisiyle parlar.','Virgo shines through service, order, analysis and meaningful small improvements.','Jungfrau strahlt durch Dienst, Ordnung, Analyse und sinnvolle kleine Verbesserungen.','aşırı eleştiri, kaygı ve kusursuzluk baskısı','overcriticism, anxiety and pressure to be perfect','Überkritik, Sorge und Perfektionsdruck'
  UNION ALL SELECT 'libra','Terazi','Libra','Waage','Terazi denge, estetik, ilişki bilinci ve adil seçimlerle anlam bulur.','Libra finds meaning through balance, aesthetics, relational awareness and fair choice.','Waage findet Sinn durch Balance, Ästhetik, Beziehungsbewusstsein und faire Wahl.','kararsızlık, memnun etme çabası ve çatışmadan kaçmak','indecision, people pleasing and avoiding conflict','Unentschlossenheit, Gefallenwollen und Konfliktvermeidung'
  UNION ALL SELECT 'scorpio','Akrep','Scorpio','Skorpion','Akrep yoğunluk, dönüşüm, sezgi ve saklı olanı görme cesaretiyle derinleşir.','Scorpio deepens through intensity, transformation, intuition and courage to see what is hidden.','Skorpion vertieft sich durch Intensität, Wandlung, Intuition und Mut zum Verborgenen.','kontrol, kıskançlık ve güvensizlikten doğan sınamalar','control, jealousy and tests born from mistrust','Kontrolle, Eifersucht und Prüfungen aus Misstrauen'
  UNION ALL SELECT 'sagittarius','Yay','Sagittarius','Schütze','Yay özgürlük, inanç, keşif ve geniş ufuklar aracılığıyla büyür.','Sagittarius grows through freedom, faith, discovery and wide horizons.','Schütze wächst durch Freiheit, Glaube, Entdeckung und weite Horizonte.','patavatsızlık, bağlanma korkusu ve ayrıntıları küçümsemek','bluntness, fear of commitment and dismissing details','Direktheit, Bindungsangst und Geringschätzung von Details'
  UNION ALL SELECT 'capricorn','Oğlak','Capricorn','Steinbock','Oğlak sorumluluk, yapı, sabır ve zamanla büyüyen başarı üzerinden ilerler.','Capricorn advances through responsibility, structure, patience and success built over time.','Steinbock geht durch Verantwortung, Struktur, Geduld und langfristigen Erfolg voran.','katılık, duyguyu ertelemek ve başarıyla değer ölçmek','rigidity, postponing feelings and measuring worth by success','Härte, Gefühlaufschub und Selbstwert durch Leistung'
  UNION ALL SELECT 'aquarius','Kova','Aquarius','Wassermann','Kova özgünlük, gelecek vizyonu, topluluk ve zihinsel bağımsızlıkla hareket eder.','Aquarius moves through originality, future vision, community and mental independence.','Wassermann bewegt sich durch Originalität, Zukunftsblick, Gemeinschaft und geistige Freiheit.','duygusal mesafe, ters köşe olma ihtiyacı ve kopukluk','emotional distance, the need to be contrary and detachment','emotionale Distanz, Widerspruchsdrang und Abkopplung'
  UNION ALL SELECT 'pisces','Balık','Pisces','Fische','Balık sezgi, merhamet, hayal gücü ve görünmeyen bağları hissetme yeteneğiyle akar.','Pisces flows through intuition, compassion, imagination and sensing invisible bonds.','Fische fließen durch Intuition, Mitgefühl, Fantasie und unsichtbare Verbindungen.','sınır kaybı, kaçış ve başkalarının yükünü taşımak','loss of boundaries, escapism and carrying others burdens','Grenzverlust, Flucht und fremde Lasten tragen'
) s
CROSS JOIN (
  SELECT 'tr' locale UNION ALL SELECT 'en' UNION ALL SELECT 'de'
) l
CROSS JOIN (
  SELECT 'personality' topic_key, 'Kişilik' title_tr, 'Personality' title_en, 'Persönlichkeit' title_de, 'gündelik davranış, refleksler ve benlik algısı' focus_tr, 'daily behavior, reflexes and self-image' focus_en, 'Alltagsverhalten, Reflexe und Selbstbild' focus_de, 'Kısa gözlem notları ve düzenli geri bildirim bu alanı güçlendirir.' practice_tr, 'Short observation notes and regular feedback strengthen this area.' practice_en, 'Kurze Beobachtungsnotizen und regelmäßiges Feedback stärken diesen Bereich.' practice_de
  UNION ALL SELECT 'love','Aşk','Love','Liebe','yakınlık, güven, çekim ve sevgi dili','intimacy, trust, attraction and love language','Nähe, Vertrauen, Anziehung und Liebessprache','İhtiyacı açık söylemek ve karşı tarafı gerçekten dinlemek bağı derinleştirir.','Naming needs clearly and listening deeply strengthen the bond.','Klare Bedürfnisse und echtes Zuhören vertiefen die Bindung.'
  UNION ALL SELECT 'career','Kariyer','Career','Beruf','motivasyon, üretim tarzı ve görünür başarı','motivation, work style and visible success','Motivation, Arbeitsstil und sichtbarer Erfolg','Hedefi küçük aşamalara bölmek ve ilerlemeyi ölçmek yön duygusu verir.','Breaking goals into milestones and measuring progress creates direction.','Ziele in Etappen zu teilen und Fortschritt zu messen schafft Richtung.'
  UNION ALL SELECT 'wellness','Ruhsal Bakım','Wellness','Selbstfürsorge','beden ritmi, duygu düzenleme ve içsel merkez','body rhythm, emotional regulation and inner center','Körperrhythmus, emotionale Regulation und innere Mitte','Nefes, hareket ve günlük tutma burcun enerjisini dengede tutar.','Breath, movement and journaling keep the sign energy balanced.','Atem, Bewegung und Schreiben halten die Zeichenenergie im Gleichgewicht.'
) t;
